"""GreenNode AgentBase runtime utilities for object conversion and serialization."""

from dataclasses import asdict, is_dataclass
from typing import Any, Dict

from ..exceptions import GreenNodeRuntimeError
from .models import AgentRuntimeAutoscaling


def convert_complex_objects(obj: Any, _depth: int = 0) -> Any:
    """Recursively convert complex objects to serializable dictionaries.

    This function handles Pydantic models, dataclasses, dictionaries, lists,
    tuples, and sets, converting them to JSON-serializable formats. It prevents
    infinite recursion by limiting the depth.

    Args:
        obj: The object to convert to a serializable format
        _depth: Internal parameter to track recursion depth (max 50)

    Returns:
        A JSON-serializable representation of the input object

    Raises:
        GreenNodeRuntimeError: If conversion fails or depth limit is exceeded

    Example:
        >>> from pydantic import BaseModel
        >>> class User(BaseModel):
        ...     name: str
        ...     age: int
        >>> user = User(name="Alice", age=30)
        >>> result = convert_complex_objects(user)
        >>> print(result)
        {'name': 'Alice', 'age': 30}
    """
    # Prevent infinite recursion
    if _depth > 50:
        raise GreenNodeRuntimeError(
            "Maximum recursion depth exceeded while converting complex objects",
            details={"max_depth": 50, "current_depth": _depth},
        )

    try:
        # Handle Pydantic models (like AIMessage)
        if hasattr(obj, "model_dump"):
            return obj.model_dump()

        # Handle dataclasses (like AgentResult)
        elif is_dataclass(obj):
            return asdict(obj)

        # Handle dictionaries recursively
        elif isinstance(obj, dict):
            return {k: convert_complex_objects(v, _depth + 1) for k, v in obj.items()}

        # Handle lists and tuples recursively
        elif isinstance(obj, (list, tuple)):
            return [convert_complex_objects(item, _depth + 1) for item in obj]

        # Handle sets (convert to list)
        elif isinstance(obj, set):
            return [convert_complex_objects(item, _depth + 1) for item in obj]

        # Return primitives as-is
        else:
            return obj
    except Exception as e:
        raise GreenNodeRuntimeError(
            "Failed to convert complex object to serializable format",
            details={"object_type": type(obj).__name__, "depth": _depth},
            cause=e,
        ) from e


def build_update_body_from_runtime(current: Any) -> Dict[str, Any]:
    """Build an update-request body dict from current runtime (DTO model or dict).

    Extracts only fields that AgentRuntimeUpdateRequest accepts. Callers should
    merge config (e.g. get_runtime_env_vars) and overrides before building
    AgentRuntimeUpdateRequest.
    
    Ensures all required fields have default values to match backend @NotNull requirements.
    """
    body: Dict[str, Any] = {}
    if hasattr(current, "image_url") and current.image_url is not None:
        body["image_url"] = current.image_url
    elif isinstance(current, dict) and (current.get("imageUrl") or current.get("image_url")):
        body["image_url"] = current.get("imageUrl") or current.get("image_url")
    if hasattr(current, "image_auth") and current.image_auth is not None:
        body["image_auth"] = current.image_auth
    elif isinstance(current, dict) and (current.get("imageAuth") or current.get("image_auth")):
        body["image_auth"] = current.get("imageAuth") or current.get("image_auth")
    
    # description: required field, default to empty string if None
    if hasattr(current, "description") and current.description is not None:
        body["description"] = current.description
    elif isinstance(current, dict) and current.get("description") is not None:
        body["description"] = current.get("description")
    else:
        body["description"] = ""
    
    # command: required field, default to empty list if None
    if hasattr(current, "command") and current.command is not None:
        body["command"] = current.command
    elif isinstance(current, dict) and current.get("command") is not None:
        body["command"] = current["command"]
    else:
        body["command"] = []
    
    # args: required field, default to empty list if None
    if hasattr(current, "args") and current.args is not None:
        body["args"] = current.args
    elif isinstance(current, dict) and current.get("args") is not None:
        body["args"] = current["args"]
    else:
        body["args"] = []
    
    # environment_variables: required field, default to empty dict if None
    if hasattr(current, "environment_variables") and current.environment_variables:
        body["environment_variables"] = dict(current.environment_variables)
    elif isinstance(current, dict) and (current.get("environmentVariables") or current.get("environment_variables")):
        env_vars = current.get("environmentVariables") or current.get("environment_variables")
        body["environment_variables"] = dict(env_vars) if env_vars else {}
    else:
        body["environment_variables"] = {}
    
    if hasattr(current, "flavor_id") and current.flavor_id is not None:
        body["flavor_id"] = current.flavor_id
    elif isinstance(current, dict) and (current.get("flavorId") or current.get("flavor_id")):
        body["flavor_id"] = current.get("flavorId") or current.get("flavor_id")
    
    # autoscaling: required field, default to AgentRuntimeAutoscaling() if None
    if hasattr(current, "autoscaling") and current.autoscaling is not None:
        body["autoscaling"] = current.autoscaling
    elif isinstance(current, dict) and current.get("autoscaling") is not None:
        a = current.get("autoscaling")
        body["autoscaling"] = AgentRuntimeAutoscaling(**a) if isinstance(a, dict) else a
    else:
        body["autoscaling"] = AgentRuntimeAutoscaling()
    return body


def is_docker_running() -> bool:
    """Check if Docker is running."""
    import docker
    try:
        docker.from_env().ping()
        return True
    except docker.errors.DockerException:
        return False